139→/// Run semantic checks on a successfully parsed config.
140→pub(super) fn check_semantic_warnings(config: &MoltisConfig, diagnostics: &mut Vec<Diagnostic>) {
141→    let is_localhost = config.server.bind == "127.0.0.1"
142→        || config.server.bind == "localhost"
143→        || config.server.bind == "::1";
144→
145→    // auth.disabled + non-localhost
146→    if config.auth.disabled && !is_localhost {
147→        diagnostics.push(Diagnostic {
148→            severity: Severity::Warning,
149→            category: "security",
150→            path: "auth".into(),
151→            message: format!(
152→                "authentication is disabled while binding to {}",
153→                config.server.bind
154→            ),
155→        });
156→    }
157→
158→    // TLS disabled + non-localhost
159→    if !config.tls.enabled && !is_localhost {
160→        diagnostics.push(Diagnostic {
161→            severity: Severity::Warning,
162→            category: "security",
163→            path: "tls".into(),
164→            message: format!("TLS is disabled while binding to {}", config.server.bind),
165→        });
166→    }
167→
168→    // TLS cert without key or vice versa
169→    let has_cert = config.tls.cert_path.is_some();
170→    let has_key = config.tls.key_path.is_some();
171→    if has_cert && !has_key {
172→        diagnostics.push(Diagnostic {
173→            severity: Severity::Error,
174→            category: "security",
175→            path: "tls".into(),
176→            message: "tls.cert_path is set but tls.key_path is missing".into(),
177→        });
178→    }
179→    if has_key && !has_cert {
180→        diagnostics.push(Diagnostic {
181→            severity: Severity::Error,
182→            category: "security",
183→            path: "tls".into(),
184→            message: "tls.key_path is set but tls.cert_path is missing".into(),
185→        });
186→    }
187→
188→    // Sandbox mode off
189→    if config.tools.exec.sandbox.mode == "off" {
190→        diagnostics.push(Diagnostic {
191→            severity: Severity::Warning,
192→            category: "security",
193→            path: "tools.exec.sandbox.mode".into(),
194→            message: "sandbox mode is disabled — commands run without isolation".into(),
195→        });
196→    }
197→
198→    // tools.fs: must_read_before_write requires track_reads
199→    if config.tools.fs.must_read_before_write && !config.tools.fs.track_reads {
200→        diagnostics.push(Diagnostic {
201→            severity: Severity::Error,
202→            category: "invalid-value",
203→            path: "tools.fs".into(),
204→            message: "must_read_before_write=true requires track_reads=true".into(),
205→        });
206→    }
207→
208→    // tools.fs.workspace_root must be absolute when set
209→    if let Some(ref root) = config.tools.fs.workspace_root
210→        && !Path::new(root).is_absolute()
211→    {
212→        diagnostics.push(Diagnostic {
213→            severity: Severity::Error,
214→            category: "invalid-value",
215→            path: "tools.fs.workspace_root".into(),
216→            message: format!("workspace_root must be an absolute path (got '{root}')"),
217→        });
218→    }
219→
220→    // tools.fs.allow_paths / deny_paths entries should be absolute
221→    for (idx, entry) in config.tools.fs.allow_paths.iter().enumerate() {
222→        if !entry.starts_with('/') && !entry.starts_with("**") {
223→            diagnostics.push(Diagnostic {
224→                severity: Severity::Warning,
225→                category: "invalid-value",
226→                path: format!("tools.fs.allow_paths[{idx}]"),
227→                message: format!(
228→                    "allow_paths entries should be absolute path globs starting with '/' (got '{entry}')"
229→                ),
230→            });
231→        }
232→    }
233→    for (idx, entry) in config.tools.fs.deny_paths.iter().enumerate() {
234→        if !entry.starts_with('/') && !entry.starts_with("**") {
235→            diagnostics.push(Diagnostic {
236→                severity: Severity::Warning,
237→                category: "invalid-value",
238→                path: format!("tools.fs.deny_paths[{idx}]"),
239→                message: format!(
240→                    "deny_paths entries should be absolute path globs starting with '/' (got '{entry}')"
241→                ),
242→            });
243→        }
244→    }
245→
246→    // upstream_proxy: must be a valid URL with a supported scheme.
247→    if let Some(ref proxy) = config.upstream_proxy {
248→        let url = proxy.expose_secret();
249→        let valid = url.starts_with("http://")
250→            || url.starts_with("https://")
251→            || url.starts_with("socks5://")
252→            || url.starts_with("socks5h://");
253→        if !valid {
254→            // Extract only the scheme portion (before "://") to avoid leaking
255→            // credentials that may be embedded in the URL.
256→            let scheme = url.split("://").next().unwrap_or("<unknown>");
257→            diagnostics.push(Diagnostic {
258→                severity: Severity::Error,
259→                category: "invalid-value",
260→                path: "upstream_proxy".into(),
261→                message: format!(
262→                    "upstream_proxy must use http://, https://, socks5://, or socks5h:// scheme (got \"{scheme}://\")"
263→                ),
264→            });
265→        }
266→    }
267→
268→    // Loop limit must be positive to avoid immediate run failures.
269→    if config.tools.agent_max_iterations == 0 {
270→        diagnostics.push(Diagnostic {
271→            severity: Severity::Error,
272→            category: "invalid-value",
273→            path: "tools.agent_max_iterations".into(),
274→            message: "tools.agent_max_iterations must be at least 1".into(),
275→        });
276→    }
277→
278→    // A zero workspace file limit would silently drop all AGENTS.md / TOOLS.md content.
279→    if config.chat.workspace_file_max_chars == 0 {
280→        diagnostics.push(Diagnostic {
281→            severity: Severity::Warning,
282→            category: "invalid-value",
283→            path: "chat.workspace_file_max_chars".into(),
284→            message: "chat.workspace_file_max_chars is 0 — AGENTS.md and TOOLS.md will be empty in the prompt".into(),
285→        });
286→    }
287→
288→    // Compaction config sanity.
289→    let compaction = &config.chat.compaction;
290→    if !(0.1..=0.95).contains(&compaction.threshold_percent) {
291→        diagnostics.push(Diagnostic {
292→            severity: Severity::Warning,
293→            category: "invalid-value",
294→            path: "chat.compaction.threshold_percent".into(),
295→            message: format!(
296→                "chat.compaction.threshold_percent = {} is outside the supported 0.1–0.95 range; the default (0.95) will be used",
297→                compaction.threshold_percent
298→            ),
299→        });
300→    }
301→    if !(0.05..=0.80).contains(&compaction.tail_budget_ratio) {
302→        diagnostics.push(Diagnostic {
303→            severity: Severity::Warning,
304→            category: "invalid-value",
305→            path: "chat.compaction.tail_budget_ratio".into(),
306→            message: format!(
307→                "chat.compaction.tail_budget_ratio = {} is outside the supported 0.05–0.80 range; the default (0.20) will be used",
308→                compaction.tail_budget_ratio
309→            ),
310→        });
311→    }
312→    if compaction.protect_head > 32 {
313→        diagnostics.push(Diagnostic {
314→            severity: Severity::Warning,
315→            category: "invalid-value",
316→            path: "chat.compaction.protect_head".into(),
317→            message: "chat.compaction.protect_head > 32 will leave little room for the compacted middle region on typical sessions".into(),
318→        });
319→    }
320→    // All four CompactionMode variants are now implemented. Any future
321→    // "not-implemented" markers would go here; leave the match explicit so
322→    // adding a new variant forces a decision at compile time.
323→    match compaction.mode {
324→        crate::schema::CompactionMode::Deterministic
325→        | crate::schema::CompactionMode::RecencyPreserving
326→        | crate::schema::CompactionMode::Structured
327→        | crate::schema::CompactionMode::LlmReplace => {},
328→    }
329→
330→    if config.mcp.request_timeout_secs == 0 {
331→        diagnostics.push(Diagnostic {
332→            severity: Severity::Error,
333→            category: "invalid-value",
334→            path: "mcp.request_timeout_secs".into(),
335→            message: "mcp.request_timeout_secs must be at least 1".into(),
336→        });
337→    }
338→
339→    for (name, server) in &config.mcp.servers {
340→        if server.request_timeout_secs == Some(0) {
341→            diagnostics.push(Diagnostic {
342→                severity: Severity::Error,
343→                category: "invalid-value",
344→                path: format!("mcp.servers.{name}.request_timeout_secs"),
345→                message: "mcp server request_timeout_secs must be at least 1".into(),
346→            });
347→        }
348→
349→        if !server.transport.is_empty()
350→            && !matches!(
351→                server.transport.as_str(),
352→                "stdio" | "sse" | "streamable-http" | "streamable_http" | "http"
353→            )
354→        {
355→            diagnostics.push(Diagnostic {
356→                severity: Severity::Warning,
357→                category: "invalid-value",
358→                path: format!("mcp.servers.{name}.transport"),
359→                message: format!(
360→                    "unknown transport type \"{}\"; expected \"stdio\", \"sse\", or \"streamable-http\"",
361→                    server.transport
362→                ),
363→            });
364→        }
365→    }
366→
367→    // Firecrawl as search provider requires an API key.  We cannot check
368→    // the FIRECRAWL_API_KEY env var here (static validation), so only emit
369→    // an Info-level hint when neither config path supplies a key.
370→    if config.tools.web.search.provider == crate::schema::SearchProvider::Firecrawl
371→        && config.tools.web.firecrawl.api_key.is_none()
372→        && config.tools.web.search.api_key.is_none()
373→        && !config.tools.web.search.duckduckgo_fallback
374→    {
375→        diagnostics.push(Diagnostic {
376→            severity: Severity::Info,
377→            category: "unknown-provider",
378→            path: "tools.web.search.provider".into(),
379→            message: "search provider is 'firecrawl' but no API key found in config \
380→                      (may be supplied at runtime via FIRECRAWL_API_KEY env var)"
381→                .into(),
382→        });
383→    }
384→
385→    // agents.default_preset should reference an existing preset key.
386→    if let Some(default_preset) = config.agents.default_preset.as_deref()
387→        && !config.agents.presets.contains_key(default_preset)
388→    {
389→        diagnostics.push(Diagnostic {
390→            severity: Severity::Warning,
391→            category: "unknown-field",
392→            path: "agents.default_preset".into(),
393→            message: format!(
394→                "default preset \"{default_preset}\" is not defined in agents.presets"
395→            ),
396→        });
397→    }
398→
399→    // Silent-misconfiguration trap: `[agents.presets.*]` tool policies apply
400→    // ONLY to sub-agents spawned via `spawn_agent`. They do NOT filter tools
401→    // for the main agent session — that is controlled exclusively by
402→    // `[tools.policy]`. Users hardening their deployment often put a deny
403→    // list under a preset and expect it to apply to the main session; it
404→    // silently doesn't. Warn when at least one preset declares
405→    // `tools.allow`/`tools.deny` while `[tools.policy]` is entirely empty.
406→    {
407→        let main_policy_empty = config.tools.policy.allow.is_empty()
408→            && config.tools.policy.deny.is_empty()
409→            && config.tools.policy.profile.is_none();
410→        if main_policy_empty {
411→            let mut offending: Vec<&str> = config
412→                .agents
413→                .presets
414→                .iter()
415→                .filter(|(_, preset)| {
416→                    !preset.tools.allow.is_empty() || !preset.tools.deny.is_empty()
417→                })
418→                .map(|(name, _)| name.as_str())
419→                .collect();
420→            if !offending.is_empty() {
421→                offending.sort_unstable();
422→                let quoted: Vec<String> =
423→                    offending.iter().map(|name| format!("\"{name}\"")).collect();
424→                diagnostics.push(Diagnostic {
425→                    severity: Severity::Warning,
426→                    category: "security",
427→                    path: "agents.presets".into(),
428→                    message: format!(
429→                        "preset(s) [{}] declare tools.allow/tools.deny, but \
430→                         [tools.policy] is empty. Preset tool policies apply \
431→                         ONLY to sub-agents spawned via the spawn_agent tool; \
432→                         they do NOT filter tools for the main agent session. \
433→                         To allow/deny tools for the main session, set \
434→                         tools.policy.allow, tools.policy.deny, or \
435→                         tools.policy.profile.",
436→                        quoted.join(", ")
437→                    ),
438→                });
439→            }
440→        }
441→    }
442→
443→    // agents.presets.*.reasoning_effort is now a typed enum (ReasoningEffort)
444→    // and validated at deserialization time (step 4). No semantic check needed.
445→
446→    // SSRF allowlist CIDR validation
447→    for (idx, entry) in config.tools.web.fetch.ssrf_allowlist.iter().enumerate() {
448→        if entry.parse::<ipnet::IpNet>().is_err() {
449→            diagnostics.push(Diagnostic {
450→                severity: Severity::Error,
451→                category: "security",
452→                path: format!("tools.web.fetch.ssrf_allowlist[{idx}]"),
453→                message: format!(
454→                    "\"{entry}\" is not a valid CIDR range (expected e.g. \"172.22.0.0/16\")"
455→                ),
456→            });
457→        }
458→    }
459→    if !config.tools.web.fetch.ssrf_allowlist.is_empty() {
460→        diagnostics.push(Diagnostic {
461→            severity: Severity::Warning,
462→            category: "security",
463→            path: "tools.web.fetch.ssrf_allowlist".into(),
464→            message: "ssrf_allowlist is set — SSRF protection is relaxed for the listed ranges. Ensure these are trusted networks.".into(),
465→        });
466→    }
467→
468→    // Unknown tool_mode values on provider entries
469→    // Note: serde rejects truly invalid values at deserialization, but if a
470→    // provider entry somehow comes through with a non-standard string we still
471→    // want to warn at the TOML level.  The enum is auto/native/text/off.
472→
473→    // Unknown channel types in channels.offered — accept built-in types plus
474→    // any dynamically configured types from `[channels.<type>]` sections.
475→    let mut valid_channel_types: Vec<&str> = crate::schema::KNOWN_CHANNEL_TYPES.to_vec();
476→    for ct in config.channels.extra.keys() {
477→        valid_channel_types.push(ct.as_str());
478→    }
479→    for (idx, entry) in config.channels.offered.iter().enumerate() {
480→        if !valid_channel_types.contains(&entry.as_str()) {
481→            diagnostics.push(Diagnostic {
482→                severity: Severity::Warning,
483→                category: "unknown-field",
484→                path: format!("channels.offered[{idx}]"),
485→                message: format!(
486→                    "unknown channel type \"{entry}\"; expected one of: {}",
487→                    valid_channel_types.join(", ")
488→                ),
489→            });
490→        }
491→    }
492→
493→    // Unknown tailscale mode
494→    let valid_ts_modes = ["off", "serve", "funnel"];
495→    if !valid_ts_modes.contains(&config.tailscale.mode.as_str()) {
496→        diagnostics.push(Diagnostic {
497→            severity: Severity::Warning,
498→            category: "unknown-field",
499→            path: "tailscale.mode".into(),
500→            message: format!(
501→                "unknown tailscale mode \"{}\"; expected one of: {}",
502→                config.tailscale.mode,
503→                valid_ts_modes.join(", ")
504→            ),
505→        });
506→    }
507→
508→    if config.ngrok.enabled && config.auth.disabled {
509→        diagnostics.push(Diagnostic {
510→            severity: Severity::Warning,
511→            category: "security",
512→            path: "ngrok.enabled".into(),
513→            message: "ngrok is enabled while auth.disabled is true; remote visitors will be blocked with setup required until authentication is configured".into(),
514→        });
515→    }
516→
517→    // Unknown sandbox backend
518→    let valid_sandbox_backends = [
519→        "auto",
520→        "docker",
521→        "podman",
522→        "apple-container",
523→        "restricted-host",
524→        "wasm",
525→    ];
526→    if !valid_sandbox_backends.contains(&config.tools.exec.sandbox.backend.as_str()) {
527→        diagnostics.push(Diagnostic {
528→            severity: Severity::Warning,
529→            category: "unknown-field",
530→            path: "tools.exec.sandbox.backend".into(),
531→            message: format!(
532→                "unknown sandbox backend \"{}\"; expected one of: {}",
533→                config.tools.exec.sandbox.backend,
534→                valid_sandbox_backends.join(", ")
535→            ),
536→        });
537→    }
538→
539→    // Unknown sandbox network policy
540→    if !config.tools.exec.sandbox.network.is_empty() {
541→        let valid_network_policies = ["blocked", "trusted", "bypass"];
542→        if !valid_network_policies.contains(&config.tools.exec.sandbox.network.as_str()) {
543→            diagnostics.push(Diagnostic {
544→                severity: Severity::Warning,
545→                category: "unknown-field",
546→                path: "tools.exec.sandbox.network".into(),
547→                message: format!(
548→                    "unknown sandbox network policy \"{}\"; expected one of: {}",
549→                    config.tools.exec.sandbox.network,
550→                    valid_network_policies.join(", ")
551→                ),
552→            });
553→        }
554→    }
555→
556→    // Unknown CalDAV provider
557→    let valid_caldav_providers = ["fastmail", "icloud", "generic"];
558→    for (name, account) in &config.caldav.accounts {
559→        if let Some(ref provider) = account.provider
560→            && !valid_caldav_providers.contains(&provider.as_str())
561→        {
562→            diagnostics.push(Diagnostic {
563→                severity: Severity::Warning,
564→                category: "unknown-field",
565→                path: format!("caldav.accounts.{name}.provider"),
566→                message: format!(
567→                    "unknown CalDAV provider \"{provider}\"; expected one of: {}",
568→                    valid_caldav_providers.join(", ")
569→                ),
570→            });
571→        }
572→    }
573→
574→    // Unknown exec host
575→    let valid_exec_hosts = ["local", "node", "ssh"];
576→    if !valid_exec_hosts.contains(&config.tools.exec.host.as_str()) {
577→        diagnostics.push(Diagnostic {
578→            severity: Severity::Warning,
579→            category: "unknown-field",
580→            path: "tools.exec.host".into(),
581→            message: format!(
582→                "unknown exec host \"{}\"; expected one of: {}",
583→                config.tools.exec.host,
584→                valid_exec_hosts.join(", ")
585→            ),
586→        });
587→    }
588→
589→    // Warn if host=node but no node specified
590→    if config.tools.exec.host == "node" && config.tools.exec.node.is_none() {
591→        diagnostics.push(Diagnostic {
592→            severity: Severity::Warning,
593→            category: "unknown-field",
594→            path: "tools.exec.node".into(),
595→            message: "tools.exec.host is \"node\" but no default node is specified; commands will fail unless a node connects".into(),
596→        });
597→    }
598→
599→    if config.tools.exec.host == "ssh" && config.tools.exec.ssh_target.is_none() {
600→        diagnostics.push(Diagnostic {
601→            severity: Severity::Warning,
602→            category: "unknown-field",
603→            path: "tools.exec.ssh_target".into(),
604→            message:
605→                "tools.exec.host is \"ssh\" but no SSH target is specified; commands will fail"
606→                    .into(),
607→        });
608→    }
609→
610→    // Unknown exec security level
611→    let valid_security_levels = ["allowlist", "permissive", "strict"];
612→    if !valid_security_levels.contains(&config.tools.exec.security_level.as_str()) {
613→        diagnostics.push(Diagnostic {
614→            severity: Severity::Warning,
615→            category: "unknown-field",
616→            path: "tools.exec.security_level".into(),
617→            message: format!(
618→                "unknown security level \"{}\"; expected one of: {}",
619→                config.tools.exec.security_level,
620→                valid_security_levels.join(", ")
621→            ),
622→        });
623→    }
624→
625→    // Unknown voice TTS providers list values
626→    let valid_voice_tts_providers = [
627→        "elevenlabs",
628→        "openai",
629→        "openai-tts",
630→        "google",
631→        "google-tts",
632→        "piper",
633→        "coqui",
634→    ];
635→    for (idx, provider) in config.voice.tts.providers.iter().enumerate() {
636→        if !valid_voice_tts_providers.contains(&provider.as_str()) {
637→            diagnostics.push(Diagnostic {
638→                severity: Severity::Warning,
639→                category: "unknown-field",
640→                path: format!("voice.tts.providers[{idx}]"),
641→                message: format!(
642→                    "unknown TTS provider \"{provider}\"; expected one of: {}",
643→                    valid_voice_tts_providers.join(", ")
644→                ),
645→            });
646→        }
647→    }
648→
649→    // Unknown voice STT providers list values
650→    let valid_voice_stt_providers = [
651→        "whisper",
652→        "groq",
653→        "deepgram",
654→        "google",
655→        "mistral",
656→        "elevenlabs",
657→        "elevenlabs-stt",
658→        "voxtral-local",
659→        "whisper-cli",
660→        "sherpa-onnx",
661→    ];
662→    for (idx, provider) in config.voice.stt.providers.iter().enumerate() {
663→        if !valid_voice_stt_providers.contains(&provider.as_str()) {
664→            diagnostics.push(Diagnostic {
665→                severity: Severity::Warning,
666→                category: "unknown-field",
667→                path: format!("voice.stt.providers[{idx}]"),
668→                message: format!(
669→                    "unknown STT provider \"{provider}\"; expected one of: {}",
670→                    valid_voice_stt_providers.join(", ")
671→                ),
672→            });
673→        }
674→    }
675→
676→    // Unknown hook event names
677→    let valid_hook_events = [
678→        "BeforeAgentStart",
679→        "AgentEnd",
680→        "BeforeLLMCall",
681→        "AfterLLMCall",
682→        "BeforeCompaction",
683→        "AfterCompaction",
684→        "MessageReceived",
685→        "MessageSending",
686→        "MessageSent",
687→        "BeforeToolCall",
688→        "AfterToolCall",
689→        "ToolResultPersist",
690→        "SessionStart",
691→        "SessionEnd",
692→        "GatewayStart",
693→        "GatewayStop",
694→        "Command",
695→    ];
696→    if let Some(ref hooks_config) = config.hooks {
697→        for (hook_idx, hook) in hooks_config.hooks.iter().enumerate() {
698→            for (ev_idx, event) in hook.events.iter().enumerate() {
699→                if !valid_hook_events.contains(&event.as_str()) {
700→                    diagnostics.push(Diagnostic {
701→                        severity: Severity::Warning,
702→                        category: "unknown-field",
703→                        path: format!("hooks.hooks[{hook_idx}].events[{ev_idx}]"),
704→                        message: format!(
705→                            "unknown hook event \"{event}\"; expected one of: {}",
706→                            valid_hook_events.join(", ")
707→                        ),
708→                    });
709→                }
710→            }
711→        }
712→    }
713→
714→    // Browser profile_dir should be an absolute path
715→    if let Some(ref dir) = config.tools.browser.profile_dir
716→        && !Path::new(dir).is_absolute()
717→    {
718→        diagnostics.push(Diagnostic {
719→            severity: Severity::Warning,
720→            category: "invalid-value",
721→            path: "tools.browser.profile_dir".into(),
722→            message: "profile_dir should be an absolute path".into(),
723→        });
724→    }
725→
726→    // port == 0
727→    if config.server.port == 0 {
728→        diagnostics.push(Diagnostic {
729→            severity: Severity::Info,
730→            category: "security",
731→            path: "server.port".into(),
732→            message: "port is 0; a random port will be assigned at startup".into(),
733→        });
734→    }
735→
736→    // Validate global model overrides.
737→    // Negative values are rejected by u32 deserialization (type error),
738→    // so we only need to guard zero and unusually large values here.
739→    for (model_id, override_cfg) in &config.models {
740→        validate_context_window(
741→            override_cfg.context_window,
742→            &format!("models.{model_id}.context_window"),
743→            diagnostics,
744→        );
745→    }
746→
747→    // Validate provider-scoped model overrides.
748→    for (provider_name, provider_entry) in &config.providers.providers {
749→        for (model_id, override_cfg) in &provider_entry.model_overrides {
750→            validate_context_window(
751→                override_cfg.context_window,
752→                &format!("providers.{provider_name}.model_overrides.{model_id}.context_window"),
753→                diagnostics,
754→            );
755→        }
756→    }
757→
758→    // tools: overflow_ratio must not be zero (budget becomes 0, every iteration fails)
759→    if config.tools.preemptive_overflow_ratio == 0 {
760→        diagnostics.push(Diagnostic {
761→            severity: Severity::Warning,
762→            category: "invalid-value",
763→            path: "tools.preemptive_overflow_ratio".into(),
764→            message: "preemptive_overflow_ratio = 0 means the overflow budget is always \
765→                      0 tokens; the agent loop will fail immediately on every iteration"
766→                .into(),
767→        });
768→    }
769→
770→    // tools: ratio fields should not exceed 100 (percentages)
771→    if config.tools.tool_result_compaction_ratio > 100 {
772→        diagnostics.push(Diagnostic {
773→            severity: Severity::Warning,
774→            category: "invalid-value",
775→            path: "tools.tool_result_compaction_ratio".into(),
776→            message: format!(
777→                "tool_result_compaction_ratio ({}) exceeds 100 — compaction will trigger on every iteration regardless of context usage",
778→                config.tools.tool_result_compaction_ratio
779→            ),
780→        });
781→    }
782→    if config.tools.preemptive_overflow_ratio > 100 {
783→        diagnostics.push(Diagnostic {
784→            severity: Severity::Warning,
785→            category: "invalid-value",
786→            path: "tools.preemptive_overflow_ratio".into(),
787→            message: format!(
788→                "preemptive_overflow_ratio ({}) exceeds 100 — overflow protection will always trigger",
789→                config.tools.preemptive_overflow_ratio
790→            ),
791→        });
792→    }
793→
794→    // tools: overflow_ratio must be greater than compaction_ratio
795→    if config.tools.tool_result_compaction_ratio > 0
796→        && config.tools.preemptive_overflow_ratio <= config.tools.tool_result_compaction_ratio
797→    {
798→        diagnostics.push(Diagnostic {
799→            severity: Severity::Warning,
800→            category: "invalid-value",
801→            path: "tools.preemptive_overflow_ratio".into(),
802→            message: format!(
803→                "preemptive_overflow_ratio ({}) should be greater than tool_result_compaction_ratio ({}) to avoid context overflow on every iteration",
804→                config.tools.preemptive_overflow_ratio, config.tools.tool_result_compaction_ratio
805→            ),
806→        });
807→    }
808→}
809→
810→/// Validate a `context_window` override value (optional field).
811→fn validate_context_window(value: Option<u32>, path: &str, diagnostics: &mut Vec<Diagnostic>) {
812→    let Some(cw) = value else {
813→        return;
814→    };
815→    if cw == 0 {
816→        diagnostics.push(Diagnostic {
817→            severity: Severity::Error,
818→            category: "invalid-value",
819→            path: path.into(),
820→            message: "context_window must be at least 1".into(),
821→        });
822→    } else if cw > 10_000_000 {
823→        diagnostics.push(Diagnostic {
824→            severity: Severity::Warning,
825→            category: "invalid-value",
826→            path: path.into(),
827→            message: format!("context_window is {cw}, which is unusually large (> 10M)"),
828→        });
829→    }
830→}
831→
832→/// Check that file paths referenced in TLS config exist on disk.
833→pub(super) fn check_file_references(
834→    toml_str: &str,
835→    _config_path: &Path,
836→    diagnostics: &mut Vec<Diagnostic>,
837→) {
838→    // Only check if we can parse the config
839→    let Ok(config) = toml::from_str::<MoltisConfig>(toml_str) else {
840→        return;
841→    };
842→
843→    let file_refs: &[(&str, &Option<String>)] = &[
844→        ("tls.cert_path", &config.tls.cert_path),
845→        ("tls.key_path", &config.tls.key_path),
846→        ("tls.ca_cert_path", &config.tls.ca_cert_path),
847→    ];
848→
849→    for (path_name, value) in file_refs {
850→        if let Some(file_path) = value {
851→            let p = Path::new(file_path);
852→            if !p.exists() {
853→                diagnostics.push(Diagnostic {
854→                    severity: Severity::Warning,
855→                    category: "file-ref",
856→                    path: (*path_name).into(),
857→                    message: format!("file not found: {file_path}"),
858→                });
859→            }
860→        }
861→    }
862→}
