 11→/// Load config from the given path (any supported format).
 12→///
 13→/// After parsing, `MOLTIS_*` env vars are applied as overrides.
 14→pub fn load_config(path: &Path) -> crate::Result<MoltisConfig> {
 15→    let raw = std::fs::read_to_string(path).map_err(|source| {
 16→        crate::Error::external(format!("failed to read {}", path.display()), source)
 17→    })?;
 18→    let raw = substitute_env(&raw);
