 32→/// Discover and load config from standard locations.
 33→///
 34→/// Search order:
 35→/// 1. `./moltis.{toml,yaml,yml,json}` (project-local)
 36→/// 2. `~/.config/moltis/moltis.{toml,yaml,yml,json}` (user-global)
 37→///
 38→/// Returns `MoltisConfig::default()` if no config file is found.
 39→///
 40→/// If the config has port 0 (either from defaults or missing `[server]` section),
 41→/// a random available port is generated and saved to the config file.
 42→pub fn discover_and_load() -> MoltisConfig {
 43→    let mut cfg = if let Some(path) = find_config_file() {
 44→        debug!(path = %path.display(), "loading config");
 45→        match load_config(&path) {
 46→            Ok(mut cfg) => {
 47→                // If port is 0 (default/missing), generate a random port and save it.
 48→                // Use `save_config_to_path` directly instead of `save_config` because
 49→                // this function may be called from within `update_config`, which already
 50→                // holds `CONFIG_SAVE_LOCK`. Re-acquiring a `std::sync::Mutex` on the
 51→                // same thread would deadlock.
 52→                if cfg.server.port == 0 {
 53→                    cfg.server.port = generate_random_port();
 54→                    debug!(
 55→                        port = cfg.server.port,
 56→                        "generated random port for existing config"
 57→                    );
 58→                    if let Err(e) = save_config_to_path(&path, &cfg) {
 59→                        warn!(error = %e, "failed to save config with generated port");
 60→                    }
 61→                }
 62→                cfg // env overrides already applied by load_config
 63→            },
 64→            Err(e) => {
 65→                warn!(path = %path.display(), error = %e, "failed to load config, using defaults");
 66→                apply_env_overrides(MoltisConfig::default())
 67→            },
 68→        }
 69→    } else {
 70→        let default_path = find_or_default_config_path();
 71→        debug!(
 72→            path = %default_path.display(),
 73→            "no config file found, writing default config with random port"
 74→        );
 75→        let mut config = MoltisConfig::default();
 76→        // Generate a unique port for this installation
 77→        config.server.port = generate_random_port();
 78→        if let Err(e) = write_default_config(&default_path, &config) {
 79→            warn!(
 80→                path = %default_path.display(),
 81→                error = %e,
 82→                "failed to write default config file, continuing with in-memory defaults"
 83→            );
 84→        } else {
 85→            info!(
 86→                path = %default_path.display(),
 87→                "wrote default config template"
 88→            );
 89→        }
 90→        apply_env_overrides(config)
 91→    };
 92→
 93→    // Merge markdown agent definitions (TOML presets take precedence).
 94→    let agent_defs = crate::agent_defs::discover_agent_defs();
 95→    if !agent_defs.is_empty() {
 96→        debug!(
 97→            count = agent_defs.len(),
 98→            "discovered markdown agent definitions"
 99→        );
100→        crate::agent_defs::merge_agent_defs(&mut cfg.agents.presets, agent_defs);
101→    }
102→
103→    cfg
104→}
