152→/// Lock guarding config read-modify-write cycles.
153→struct ConfigSaveState {
154→    target_path: Option<PathBuf>,
155→}
156→
157→/// Lock guarding config read-modify-write cycles and the target config path
158→/// being synchronized.
159→static CONFIG_SAVE_LOCK: Mutex<ConfigSaveState> = Mutex::new(ConfigSaveState { target_path: None });
160→
161→/// Atomically load the current config, apply `f`, and save.
162→///
163→/// Acquires a process-wide lock so concurrent callers cannot race.
164→/// Returns the path written to.
165→pub fn update_config(f: impl FnOnce(&mut MoltisConfig)) -> crate::Result<PathBuf> {
166→    let mut guard = CONFIG_SAVE_LOCK.lock().unwrap_or_else(|e| e.into_inner());
167→    let target_path = find_or_default_config_path();
168→    guard.target_path = Some(target_path.clone());
169→    let mut config = discover_and_load();
170→    f(&mut config);
171→    save_config_to_path(&target_path, &config)
172→}
173→
174→/// Serialize `config` to TOML and write it to the user-global config path.
175→///
176→/// Creates parent directories if needed. Returns the path written to.
177→///
178→/// Prefer [`update_config`] for read-modify-write cycles to avoid races.
179→pub fn save_config(config: &MoltisConfig) -> crate::Result<PathBuf> {
180→    let mut guard = CONFIG_SAVE_LOCK.lock().unwrap_or_else(|e| e.into_inner());
181→    let target_path = find_or_default_config_path();
182→    guard.target_path = Some(target_path.clone());
183→    save_config_to_path(&target_path, config)
184→}
185→
186→/// Write raw TOML to the config file, preserving comments.
187→///
188→/// Validates the input by parsing it first. Acquires the config save lock
189→/// so concurrent callers cannot race.  Returns the path written to.
190→pub fn save_raw_config(toml_str: &str) -> crate::Result<PathBuf> {
191→    let _: MoltisConfig = toml::from_str(toml_str)
192→        .map_err(|source| crate::Error::external(format!("invalid config: {source}"), source))?;
193→    let mut guard = CONFIG_SAVE_LOCK.lock().unwrap_or_else(|e| e.into_inner());
194→    let path = find_or_default_config_path();
195→    guard.target_path = Some(path.clone());
196→    if let Some(parent) = path.parent() {
197→        std::fs::create_dir_all(parent)?;
198→    }
199→    std::fs::write(&path, toml_str)?;
200→    debug!(path = %path.display(), "saved raw config");
201→    Ok(path)
202→}
203→
204→/// Serialize `config` to TOML and write it to the provided path.
205→///
206→/// For existing TOML files, this preserves user comments by merging the new
207→/// serialized values into the current document structure before writing.
208→pub fn save_config_to_path(path: &Path, config: &MoltisConfig) -> crate::Result<PathBuf> {
209→    if let Some(parent) = path.parent() {
210→        std::fs::create_dir_all(parent)?;
211→    }
212→    let toml_str = toml::to_string_pretty(config)
213→        .map_err(|source| crate::Error::external("serialize config", source))?;
214→
215→    let is_toml_path = path
216→        .extension()
217→        .and_then(|ext| ext.to_str())
218→        .is_some_and(|ext| ext.eq_ignore_ascii_case("toml"));
219→
220→    if is_toml_path && path.exists() {
221→        if let Err(error) = merge_toml_preserving_comments(path, &toml_str) {
222→            warn!(
223→                path = %path.display(),
224→                error = %error,
225→                "failed to preserve TOML comments, rewriting config without comments"
226→            );
227→            std::fs::write(path, toml_str)?;
228→        }
229→    } else {
230→        std::fs::write(path, toml_str)?;
231→    }
232→
233→    debug!(path = %path.display(), "saved config");
234→    Ok(path.to_path_buf())
235→}
236→
237→fn merge_toml_preserving_comments(path: &Path, updated_toml: &str) -> crate::Result<()> {
238→    let current_toml = std::fs::read_to_string(path)?;
239→    let mut current_doc = current_toml
240→        .parse::<toml_edit::DocumentMut>()
241→        .map_err(|source| crate::Error::external("parse existing TOML", source))?;
242→    let updated_doc = updated_toml
243→        .parse::<toml_edit::DocumentMut>()
244→        .map_err(|source| crate::Error::external("parse updated TOML", source))?;
245→
246→    merge_toml_tables(current_doc.as_table_mut(), updated_doc.as_table());
247→    std::fs::write(path, current_doc.to_string())?;
248→    Ok(())
249→}
250→
251→pub(super) fn merge_toml_tables(current: &mut toml_edit::Table, updated: &toml_edit::Table) {
252→    let current_keys: Vec<String> = current.iter().map(|(key, _)| key.to_string()).collect();
253→    for key in current_keys {
254→        if !updated.contains_key(&key) {
255→            let _ = current.remove(&key);
256→        }
257→    }
258→
259→    for (key, updated_item) in updated.iter() {
260→        if let Some(current_item) = current.get_mut(key) {
261→            merge_toml_items(current_item, updated_item);
262→        } else {
263→            // Clone the item and strip `doc_position` metadata inherited from
264→            // the source document.  Without this, toml_edit uses the position
265→            // from the *serialized* document, causing new sub-tables to be
266→            // interleaved among existing sections instead of appearing after
267→            // their parent (GH-684).
268→            current.insert(key, clone_item_without_positions(updated_item));
269→        }
270→    }
271→}
272→
273→/// Deep-clone a `toml_edit::Item`, stripping `doc_position` from every table
274→/// so that newly inserted entries get auto-positioned by `toml_edit` rather
275→/// than inheriting stale positions from a different document.
276→fn clone_item_without_positions(item: &toml_edit::Item) -> toml_edit::Item {
277→    match item {
278→        toml_edit::Item::Table(t) => toml_edit::Item::Table(clone_table_without_positions(t)),
279→        toml_edit::Item::ArrayOfTables(arr) => {
280→            let mut new_arr = toml_edit::ArrayOfTables::new();
281→            for table in arr.iter() {
282→                new_arr.push(clone_table_without_positions(table));
283→            }
284→            toml_edit::Item::ArrayOfTables(new_arr)
285→        },
286→        other => other.clone(),
287→    }
288→}
289→
290→/// Clone a table, recursively stripping `doc_position` so new tables get
291→/// auto-positioned when inserted into a different document.
292→fn clone_table_without_positions(src: &toml_edit::Table) -> toml_edit::Table {
293→    let mut dst = toml_edit::Table::new();
294→    // doc_position is None for manually created tables → auto-positioned
295→    dst.set_implicit(src.is_implicit());
296→    dst.set_dotted(src.is_dotted());
297→    *dst.decor_mut() = src.decor().clone();
298→    for (key, item) in src.iter() {
299→        dst.insert(key, clone_item_without_positions(item));
300→        // Preserve key decorations (whitespace/comments around the key)
301→        if let (Some(src_key), Some(mut dst_key)) = (src.key(key), dst.key_mut(key)) {
302→            *dst_key.leaf_decor_mut() = src_key.leaf_decor().clone();
303→            *dst_key.dotted_decor_mut() = src_key.dotted_decor().clone();
304→        }
305→    }
306→    dst
307→}
308→
309→fn merge_toml_items(current: &mut toml_edit::Item, updated: &toml_edit::Item) {
310→    match (current, updated) {
311→        (toml_edit::Item::Table(current_table), toml_edit::Item::Table(updated_table)) => {
312→            merge_toml_tables(current_table, updated_table);
313→        },
314→        (toml_edit::Item::Value(current_value), toml_edit::Item::Value(updated_value)) => {
315→            let existing_decor = current_value.decor().clone();
316→            *current_value = updated_value.clone();
317→            *current_value.decor_mut() = existing_decor;
318→        },
319→        (current_item, updated_item) => {
320→            *current_item = updated_item.clone();
321→        },
322→    }
323→}
324→
325→/// Write the default config file to the user-global config path.
326→/// Only called when no config file exists yet.
327→/// Uses a comprehensive template with all options documented.
328→pub(super) fn write_default_config(path: &Path, config: &MoltisConfig) -> crate::Result<()> {
329→    if path.exists() {
330→        return Ok(());
331→    }
332→    if let Some(parent) = path.parent() {
333→        std::fs::create_dir_all(parent)?;
334→    }
335→    // Use the documented template instead of plain serialization
336→    let toml_str = crate::template::default_config_template(config.server.port);
337→    std::fs::write(path, &toml_str)?;
338→    debug!(path = %path.display(), "wrote default config file with template");
339→    Ok(())
340→}
341→
342→/// Apply `MOLTIS_*` environment variable overrides to a loaded config.
343→///
344→/// Maps env vars to config fields using `__` as a section separator and
345→/// lowercasing. For example:
346→/// - `MOLTIS_AUTH_DISABLED=true` → `auth.disabled = true`
347→/// - `MOLTIS_TOOLS_EXEC_DEFAULT_TIMEOUT_SECS=60` → `tools.exec.default_timeout_secs = 60`
348→/// - `MOLTIS_CHAT_MESSAGE_QUEUE_MODE=collect` → `chat.message_queue_mode = "collect"`
349→///
350→/// The config is serialized to a JSON value, env overrides are merged in,
351→/// then deserialized back. Only env vars with the `MOLTIS_` prefix are
352→/// considered. `MOLTIS_CONFIG_DIR`, `MOLTIS_DATA_DIR`, `MOLTIS_SHARE_DIR`,
353→/// `MOLTIS_ASSETS_DIR`, `MOLTIS_TOKEN`, `MOLTIS_PASSWORD`, `MOLTIS_TAILSCALE`,
354→/// `MOLTIS_WEBAUTHN_RP_ID`, and `MOLTIS_WEBAUTHN_ORIGIN` are excluded
355→/// (they are handled separately).
356→pub fn apply_env_overrides(config: MoltisConfig) -> MoltisConfig {
357→    apply_env_overrides_with(config, std::env::vars())
358→}
359→
360→/// Apply env overrides from an arbitrary iterator of (key, value) pairs.
361→/// Exposed for testing without mutating the process environment.
362→pub(super) fn apply_env_overrides_with(
363→    config: MoltisConfig,
364→    vars: impl Iterator<Item = (String, String)>,
365→) -> MoltisConfig {
366→    use serde_json::Value;
367→
368→    const EXCLUDED: &[&str] = &[
369→        "MOLTIS_CONFIG_DIR",
370→        "MOLTIS_DATA_DIR",
371→        "MOLTIS_SHARE_DIR",
372→        "MOLTIS_ASSETS_DIR",
373→        "MOLTIS_TOKEN",
374→        "MOLTIS_PASSWORD",
375→        "MOLTIS_TAILSCALE",
376→        "MOLTIS_WEBAUTHN_RP_ID",
377→        "MOLTIS_WEBAUTHN_ORIGIN",
378→    ];
379→
380→    let mut root: Value = match serde_json::to_value(&config) {
381→        Ok(v) => v,
382→        Err(e) => {
383→            warn!(error = %e, "failed to serialize config for env override");
384→            return config;
385→        },
386→    };
387→
388→    for (key, val) in vars {
389→        if !key.starts_with("MOLTIS_") {
390→            continue;
391→        }
392→        if EXCLUDED.contains(&key.as_str()) {
393→            continue;
394→        }
395→
396→        // MOLTIS_AUTH__DISABLED → ["auth", "disabled"]
397→        let path_parts: Vec<String> = key["MOLTIS_".len()..]
398→            .split("__")
399→            .map(|segment| segment.to_lowercase())
400→            .collect();
401→
402→        if path_parts.is_empty() {
403→            continue;
404→        }
405→
406→        // Navigate to the parent object and set the leaf value.
407→        let parsed_val = parse_env_value(&val);
408→        set_nested(&mut root, &path_parts, parsed_val);
409→    }
410→
411→    match serde_json::from_value(root) {
412→        Ok(cfg) => cfg,
413→        Err(e) => {
414→            warn!(error = %e, "failed to apply env overrides, using config as-is");
415→            config
416→        },
417→    }
418→}
419→
420→/// Parse a string env value into a JSON value, trying bool and number first.
421→pub(super) fn parse_env_value(val: &str) -> serde_json::Value {
422→    let trimmed = val.trim();
423→
424→    // Support JSON arrays/objects for list-like env overrides, e.g.
425→    // MOLTIS_PROVIDERS__OFFERED='["openai","github-copilot"]' or '[]'.
426→    if ((trimmed.starts_with('[') && trimmed.ends_with(']'))
427→        || (trimmed.starts_with('{') && trimmed.ends_with('}')))
428→        && let Ok(parsed) = serde_json::from_str::<serde_json::Value>(trimmed)
429→    {
430→        return parsed;
431→    }
432→
433→    if val.eq_ignore_ascii_case("true") {
434→        return serde_json::Value::Bool(true);
435→    }
436→    if val.eq_ignore_ascii_case("false") {
437→        return serde_json::Value::Bool(false);
438→    }
439→    if let Ok(n) = val.parse::<i64>() {
440→        return serde_json::Value::Number(n.into());
441→    }
442→    if let Ok(n) = val.parse::<f64>()
443→        && let Some(n) = serde_json::Number::from_f64(n)
444→    {
445→        return serde_json::Value::Number(n);
446→    }
447→    serde_json::Value::String(val.to_string())
448→}
449→
450→/// Set a value at a nested JSON path, creating intermediate objects as needed.
451→pub(super) fn set_nested(root: &mut serde_json::Value, path: &[String], val: serde_json::Value) {
452→    if path.is_empty() {
453→        return;
454→    }
455→    let mut current = root;
456→    for (i, key) in path.iter().enumerate() {
457→        if i == path.len() - 1 {
458→            if let serde_json::Value::Object(map) = current {
459→                map.insert(key.clone(), val);
460→            }
461→            return;
462→        }
463→        if !current.get(key).is_some_and(|v| v.is_object())
464→            && let serde_json::Value::Object(map) = current
465→        {
466→            map.insert(key.clone(), serde_json::Value::Object(Default::default()));
467→        }
468→        let Some(next) = current.get_mut(key) else {
469→            return;
470→        };
471→        current = next;
472→    }
473→}
474→
475→pub(super) fn parse_config(raw: &str, path: &Path) -> crate::Result<MoltisConfig> {
476→    let ext = path.extension().and_then(|e| e.to_str()).unwrap_or("toml");
477→
478→    match ext {
479→        "toml" => Ok(toml::from_str(raw)?),
480→        "yaml" | "yml" => Ok(serde_yaml::from_str(raw)?),
481→        "json" => Ok(serde_json::from_str(raw)?),
482→        _ => Err(crate::Error::message(format!(
483→            "unsupported config format: .{ext}"
484→        ))),
485→    }
486→}
487→
488→fn parse_config_value(raw: &str, path: &Path) -> crate::Result<serde_json::Value> {
489→    let ext = path.extension().and_then(|e| e.to_str()).unwrap_or("toml");
490→
491→    match ext {
492→        "toml" => {
493→            let v: toml::Value = toml::from_str(raw)?;
494→            Ok(serde_json::to_value(v)?)
495→        },
496→        "yaml" | "yml" => {
497→            let v: serde_yaml::Value = serde_yaml::from_str(raw)?;
498→            Ok(serde_json::to_value(v)?)
499→        },
500→        "json" => Ok(serde_json::from_str(raw)?),
501→        _ => Err(crate::Error::message(format!(
502→            "unsupported config format: .{ext}"
503→        ))),
504→    }
505→}
