 127→async fn build_webauthn_registry(
 128→    config: &moltis_config::MoltisConfig,
 129→    port: u16,
 130→) -> anyhow::Result<Option<crate::auth_webauthn::SharedWebAuthnRegistry>> {
 131→    let default_scheme = if config.tls.enabled {
 132→        "https"
 133→    } else {
 134→        "http"
 135→    };
 136→
 137→    let explicit_rp_id = std::env::var("MOLTIS_WEBAUTHN_RP_ID")
 138→        .or_else(|_| std::env::var("APP_DOMAIN"))
 139→        .or_else(|_| std::env::var("RENDER_EXTERNAL_HOSTNAME"))
 140→        .or_else(|_| std::env::var("FLY_APP_NAME").map(|name| format!("{name}.fly.dev")))
 141→        .or_else(|_| std::env::var("RAILWAY_PUBLIC_DOMAIN"))
 142→        .ok();
 143→    let explicit_origin = std::env::var("MOLTIS_WEBAUTHN_ORIGIN")
 144→        .or_else(|_| std::env::var("APP_URL"))
 145→        .or_else(|_| std::env::var("RENDER_EXTERNAL_URL"))
 146→        .ok();
 147→
 148→    let mut wa_registry = crate::auth_webauthn::WebAuthnRegistry::new();
 149→    let mut any_ok = false;
 150→
 151→    let mut try_add = |rp_id: &str, origin_str: &str, extras: &[webauthn_rs::prelude::Url]| {
 152→        let rp_id = crate::auth_webauthn::normalize_host(rp_id);
 153→        if rp_id.is_empty() || wa_registry.contains_host(&rp_id) {
 154→            return;
 155→        }
 156→        let Ok(origin_url) = webauthn_rs::prelude::Url::parse(origin_str) else {
 157→            tracing::warn!("invalid WebAuthn origin URL '{origin_str}'");
 158→            return;
 159→        };
 160→        match crate::auth_webauthn::WebAuthnState::new(&rp_id, &origin_url, extras) {
 161→            Ok(wa) => {
 162→                info!(rp_id = %rp_id, origins = ?wa.get_allowed_origins(), "WebAuthn RP registered");
 163→                wa_registry.add(rp_id.clone(), wa);
 164→                any_ok = true;
 165→            },
 166→            Err(e) => tracing::warn!(rp_id = %rp_id, "failed to init WebAuthn: {e}"),
 167→        }
 168→    };
 169→
 170→    if let Some(ref rp_id) = explicit_rp_id {
 171→        let origin = explicit_origin
 172→            .clone()
 173→            .unwrap_or_else(|| format!("https://{rp_id}"));
 174→        try_add(rp_id, &origin, &[]);
 175→    } else {
 176→        let localhost_origin = format!("{default_scheme}://localhost:{port}");
 177→        let moltis_localhost: Vec<webauthn_rs::prelude::Url> = webauthn_rs::prelude::Url::parse(
 178→            &format!("{default_scheme}://moltis.localhost:{port}"),
 179→        )
 180→        .into_iter()
 181→        .collect();
 182→        try_add("localhost", &localhost_origin, &moltis_localhost);
 183→
 184→        let instance_slug_value = instance_slug(config);
 185→        if instance_slug_value != "localhost" {
 186→            let bot_origin = format!("{default_scheme}://{instance_slug_value}:{port}");
 187→            try_add(&instance_slug_value, &bot_origin, &[]);
 188→
 189→            let bot_local = format!("{instance_slug_value}.local");
 190→            let bot_local_origin = format!("{default_scheme}://{bot_local}:{port}");
 191→            try_add(&bot_local, &bot_local_origin, &[]);
 192→        }
 193→
 194→        if let Ok(hn) = hostname::get() {
 195→            let hn_str = hn.to_string_lossy();
 196→            if hn_str != "localhost" {
 197→                let local_name = if hn_str.ends_with(".local") {
 198→                    hn_str.to_string()
 199→                } else {
 200→                    format!("{hn_str}.local")
 201→                };
 202→                let local_origin = format!("{default_scheme}://{local_name}:{port}");
 203→                try_add(&local_name, &local_origin, &[]);
 204→
 205→                let bare = hn_str.strip_suffix(".local").unwrap_or(&hn_str);
 206→                if bare != local_name {
 207→                    let bare_origin = format!("{default_scheme}://{bare}:{port}");
 208→                    try_add(bare, &bare_origin, &[]);
 209→                }
 210→            }
 211→        }
 212→    }
 213→
 214→    if any_ok {
 215→        info!(origins = ?wa_registry.get_all_origins(), "WebAuthn passkeys enabled");
 216→        Ok(Some(Arc::new(tokio::sync::RwLock::new(wa_registry))))
 217→    } else {
 218→        Ok(None)
 219→    }
 220→}
