23→pub(super) fn check_deprecated_fields(
24→    toml_value: &toml::Value,
25→    diagnostics: &mut Vec<Diagnostic>,
26→) -> Vec<&'static str> {
27→    let Some(memory) = toml_value.get("memory").and_then(|value| value.as_table()) else {
28→        return Vec::new();
29→    };
30→
31→    let mut conflicting_replacements = Vec::new();
32→    if check_deprecated_memory_field(memory, "embedding_provider", "provider", diagnostics) {
33→        conflicting_replacements.push("provider");
34→    }
35→    if check_deprecated_memory_field(memory, "embedding_base_url", "base_url", diagnostics) {
36→        conflicting_replacements.push("base_url");
37→    }
38→    if check_deprecated_memory_field(memory, "embedding_model", "model", diagnostics) {
39→        conflicting_replacements.push("model");
40→    }
41→    if check_deprecated_memory_field(memory, "embedding_api_key", "api_key", diagnostics) {
42→        conflicting_replacements.push("api_key");
43→    }
44→    check_deprecated_ignored_memory_field(
45→        memory,
46→        "embedding_dimensions",
47→        "deprecated field; ignored because embedding dimensions are determined by the provider response",
48→        diagnostics,
49→    );
50→    conflicting_replacements
51→}
52→
53→pub(super) fn should_suppress_deprecated_conflict_type_error(
54→    message: &str,
55→    conflicting_replacements: &[&str],
56→) -> bool {
57→    conflicting_replacements
58→        .iter()
59→        .any(|replacement| message.contains(&format!("duplicate field `{replacement}`")))
60→}
61→
62→fn check_deprecated_memory_field(
63→    memory: &toml::map::Map<String, toml::Value>,
64→    legacy: &str,
65→    replacement: &str,
66→    diagnostics: &mut Vec<Diagnostic>,
67→) -> bool {
68→    if !memory.contains_key(legacy) {
69→        return false;
70→    }
71→
72→    if memory.contains_key(replacement) {
73→        diagnostics.push(Diagnostic {
74→            severity: Severity::Error,
75→            category: "deprecated-field",
76→            path: format!("memory.{legacy}"),
77→            message: format!(
78→                "deprecated field conflicts with \"memory.{replacement}\"; remove \"memory.{legacy}\""
79→            ),
80→        });

