 922→/// GH-684: section order must be preserved after a save roundtrip.
 923→#[test]
 924→fn gh684_template_section_order_preserved_after_save() {
 925→    let dir = tempfile::tempdir().expect("tempdir");
 926→    let path = dir.path().join("moltis.toml");
 927→    let template = crate::template::default_config_template(18789);
 928→    std::fs::write(&path, &template).expect("write template");
 929→
 930→    let template_sections: Vec<String> = template
 931→        .lines()
 932→        .filter(|l| l.starts_with('['))
 933→        .map(|l| l.to_string())
 934→        .collect();
 935→
 936→    // Load, modify, save — simulating a web UI setting change
 937→    let raw = std::fs::read_to_string(&path).expect("read");
 938→    let mut config: MoltisConfig = parse_config(&raw, &path).expect("parse");
 939→    config.auth.disabled = true;
 940→    config.server.http_request_logs = true;
 941→
 942→    save_config_to_path(&path, &config).expect("save config");
 943→
 944→    let saved = std::fs::read_to_string(&path).expect("read saved");
 945→    let saved_sections: Vec<String> = saved
 946→        .lines()
 947→        .filter(|l| l.starts_with('['))
 948→        .map(|l| l.to_string())
 949→        .collect();
 950→
 951→    // Every template section must still exist in the saved file
 952→    for ts in &template_sections {
 953→        assert!(
 954→            saved_sections.contains(ts),
 955→            "template section {ts} missing from saved file"
 956→        );
 957→    }
 958→
 959→    // Template sections must maintain their relative order
 960→    let template_positions: Vec<usize> = template_sections
 961→        .iter()
 962→        .map(|ts| {
 963→            saved_sections
 964→                .iter()
 965→                .position(|ss| ss == ts)
 966→                .unwrap_or_else(|| panic!("section {ts} not found in saved"))
 967→        })
 968→        .collect();
 969→    for window in template_positions.windows(2) {
 970→        assert!(
 971→            window[0] < window[1],
 972→            "template sections swapped: saved position {} >= {} \
 973→                 (sections around index {})",
 974→            window[0],
 975→            window[1],
 976→            window[0],
 977→        );
 978→    }
 979→}
