 995→    let updated = r#"[server]
 996→port = 8080
 997→
 998→[channels]
 999→offered = ["telegram"]
1000→
1001→[channels.telegram]
1002→token = "abc"
1003→
1004→[channels.whatsapp]
1005→token = "xyz"
1006→
1007→[memory]
1008→enabled = true
1009→"#;
1010→
1011→    let mut current_doc = original.parse::<toml_edit::DocumentMut>().unwrap();
1012→    let updated_doc = updated.parse::<toml_edit::DocumentMut>().unwrap();
